export const createBlockade = async (
  body: CreateBlockadeBody,
  options?: RequestInit,
): Promise<Blockade> => {
  return customFetch<Blockade>(`/api/blockades`, {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
};

